class Solution {
    public boolean equalFrequency(String word) {
        int[] freq = new int[26];
        for (char c : word.toCharArray()) {
            freq[c - 'a']++;
        }
        int count = 0;
        int maxFreq = 0, minFreq = word.length();
        int maxCount = 0, minCount = 0;
        for (int f : freq) {
            if (f > 0) {
                count++;
                maxFreq = Math.max(maxFreq, f);
                minFreq = Math.min(minFreq, f);
            }
        }
        for (int f : freq) {
            if (f == maxFreq) maxCount++;
            if (f == minFreq && f > 0) minCount++;
        }
        return (maxFreq - minFreq == 1 && maxCount == 1) || (minFreq == 1 && minCount == 1) || (count == 1);
    }
}
